queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?ballrooms a :Ballrooms .
    ?ballrooms p:name ?name .
    ?ballrooms p:seating_capacity ?seating_capacity_f .
    FILTER((STR(?seating_capacity_f) = "100" || STR(?seating_capacity_f) = "100.0"))
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?greenrooms a :GreenRooms .
    ?greenrooms p:name ?name .
    ?greenrooms p:seating_capacity ?seating_capacity_f .
    FILTER((STR(?seating_capacity_f) = "100" || STR(?seating_capacity_f) = "100.0"))
    BIND(?name AS ?o0)
  }
}

